mapper.select:
SELECT tb_schedule.*, tb_user.nick_name, tb_meeting.meeting_name AS meetingRoomName FROM tb_schedule LEFT JOIN tb_user ON tb_schedule.user_id = tb_user.id AND tb_user.is_deleted = 0 LEFT JOIN tb_meeting ON tb_schedule.meeting_room_id = tb_meeting.id AND tb_meeting.is_deleted = 0 WHERE tb_schedule.is_deleted = 0
AND tb_schedule.user_id = #{userId}
AND (tb_schedule.user_id = #{userId} OR (tb_schedule.is_public = 1 AND tb_schedule.schedule_type = 2) OR tb_schedule.id IN (SELECT sp.schedule_id FROM tb_schedule_participant sp WHERE sp.user_id = #{userId} AND sp.is_deleted = 0))
AND tb_schedule.title LIKE CONCAT('%', #{dto.title, jdbcType=VARCHAR}, '%')
AND tb_schedule.schedule_type = #{dto.scheduleType, jdbcType=TINYINT}
AND tb_schedule.start_time >= #{dto.startTimeBegin, jdbcType=VARCHAR}
AND tb_schedule.start_time <= #{dto.startTimeEnd, jdbcType=VARCHAR}
ORDER BY tb_schedule.start_time DESC
